protected void initPSAManageInvoiceTmp(TableId _tableID)
{
    FWFTextBlockReportTextInit textBlockReportTextInitHeader, textBlockReportTextInitLine;

    next initPSAManageInvoiceTmp(_tableID);

    textBlockReportTextInitHeader = FWFTextBlockReportTextInit::newParameters(this.tmpPSAManageInvoice, this.projInvoiceJour);
    textBlockReportTextInitHeader.insTexts();

    if (_tableID == tableNum(ProjInvoiceItem))
    {
        textBlockReportTextInitHeader.parmSource(this.projInvoiceItem);
        textBlockReportTextInitHeader.insLineTexts();
    }
}
